import {
  BookOutlined,
  CloseOutlined,
  DeploymentUnitOutlined,
  FolderOpenOutlined,
  MenuFoldOutlined,
  UserOutlined,
} from '@ant-design/icons';
import { Button, Drawer, Flex, theme } from 'antd';
import { useEffect, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { MainLayoutSidebar } from './_sidebar';

const NavbarButton: React.FC<{
  label: string;
  icon: React.ReactNode;
  active?: boolean;
  onClick: React.MouseEventHandler<HTMLDivElement>;
}> = ({ label, icon, active, onClick }) => {
  const { token } = theme.useToken();
  return (
    <Flex
      gap={0}
      vertical
      align="center"
      onClick={onClick}
      style={{
        flex: 1,
        cursor: 'pointer',
        userSelect: 'none',
        padding: '8px 16px',
        ...(active
          ? {
              opacity: 1,
              color: token.colorSuccess,
              boxShadow: `inset 0 -2px 2px #f48c4833`,
              background: `linear-gradient(to top, #f48c4810 0%, transparent 80%)`,
            }
          : {
              opacity: 0.9,
              color: token.colorText,
            }),
      }}
    >
      <div style={{ fontSize: 18 }}>{icon}</div>
      <div style={{ fontSize: 11, fontWeight: 500 }}>{label}</div>
    </Flex>
  );
};

export const MobileNavbar: React.FC<{
  style?: React.CSSProperties;
}> = ({ style }) => {
  const navigate = useNavigate();
  const { token } = theme.useToken();
  const { pathname: currentPath } = useLocation();
  const [drawerOpen, setDrawerOpen] = useState(false);

  useEffect(() => {
    queueMicrotask(() => setDrawerOpen(false));
  }, [currentPath]);

  const handleNavClick = (path: string) => {
    navigate(path);
  };

  return (
    <>
      <Flex
        gap={4}
        align="center"
        justify="space-between"
        style={{
          position: 'fixed',
          bottom: 0,
          left: 0,
          right: 0,
          zIndex: 1000,
          padding: '0 5px',
          userSelect: 'none',
          background: token.colorBgContainer,
          boxShadow: '0 -2px 8px rgba(0, 0, 0, 0.06)',
          borderTop: `1px solid ${token.colorBorderSecondary}`,
          ...style,
        }}
      >
        <NavbarButton
          label="Requests"
          icon={<DeploymentUnitOutlined />}
          active={currentPath === '/'}
          onClick={() => handleNavClick('/')}
        />
        <NavbarButton
          label="Novels"
          icon={<BookOutlined />}
          active={currentPath === '/novels'}
          onClick={() => handleNavClick('/novels')}
        />
        <NavbarButton
          label="Libraries"
          icon={<FolderOpenOutlined />}
          active={currentPath === '/libraries'}
          onClick={() => handleNavClick('/libraries')}
        />
        <NavbarButton
          label="Account"
          icon={<UserOutlined />}
          active={currentPath === '/profile'}
          onClick={() => handleNavClick('/profile')}
        />
        <NavbarButton
          label="More"
          icon={<MenuFoldOutlined />}
          onClick={() => setDrawerOpen((v) => !v)}
        />
      </Flex>

      <Drawer
        open={drawerOpen}
        size={250}
        closable={false}
        placement="right"
        destroyOnHidden
        onClose={() => setDrawerOpen(false)}
        styles={{ body: { padding: 0 } }}
      >
        <MainLayoutSidebar fullWidth />
        <Button
          type="text"
          shape="circle"
          icon={<CloseOutlined />}
          onClick={() => setDrawerOpen(false)}
          style={{ position: 'absolute', top: 10, right: 10, zIndex: 5 }}
        />
      </Drawer>
    </>
  );
};
